                'positionId' => $positionId,
                'timestamp' => $timestamp,
            );
            $response = Async\await($this->privatePostTradeAddMargin ($this->extend($request, $params)));
            //
            //    {
            //        "code" => "200000",
            //        "data" => {
            //            "symbol" => "BTCINR",
