    public function fetch_orders_by_status($status, ?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()) {
        return Async\async(function () use ($status, $symbol, $since, $limit, $params) {
            /**
             * fetches a list of $orders placed on the exchange
             *
             * @see https://github.com/zebpay/zebpay-api-references/blob/main/futures/api-reference/private-endpoints/trade.md#-get-open-$orders
             *
             * @param {string} $status opn $orders
             * @param {string} $symbol unified $symbol for the $market to retrieve $orders from
             * @param {int} [$since] timestamp in ms of the earliest order to retrieve
             * @param {int} [$limit] The maximum number of $orders to retrieve
             * @param {array} [$params] exchange specific parameters
             * @return An ~@link https://docs.ccxt.com/#/?id=order-structure array of order structures~
             */
            Async\await($this->load_markets());
            $request = array();
            $market = null;
            if ($symbol !== null) {
                $market = $this->market($symbol);
                $request['symbol'] = $market['id'];
            }
            if ($since !== null) {
                $request['since'] = $since || Date.now ();
            }
            if ($limit !== null) {
                $request['limit'] = $limit || 100;
            }
            $response = Async\await($this->privateGetTradeOrderOpenOrders ($this->extend($request, $params)));
            if ($response->statusCode !== 200) {
                throw new ExchangeError(json_encode ($response));
            }
            //
            //     {
            //         "data" => {
            //             "nextTimeStamp" => null,
            //             "totalCount" => 100,
            //             "data" => array(
            //                 {
            //                     "clientOrderId" => "64507d02921f1c0001ff6892-123-zeb",
            //                     "datetime" => "2025-03-14T14:34:34.4567",
            //                     "timestamp" => 1741962557553,
            //                     "status" => "open",
            //                     "symbol" => "BTCINR",
            //                     "type" => "market",
            //                     "timeInForce" => "GTC",
            //                     "side" => "buy",
            //                     "price" => 700000,
            //                     "amount" => 0.002,
            //                     "filled" => null,
            //                     "remaining" => 0.002,
            //                     "trades" => array()
            //                 }
            //             )
            //         }
            //     }
            //
            $responseData = $this->safe_value($response, 'data', array());
            $orders = $this->safe_list($responseData, 'data', array());
            return $this->parse_orders($orders, $market, $since, $limit);
        }) ();
    }

    public function fetch_open_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * fetches information on multiple open orders made by the user
             *
             * @see https://github.com/zebpay/zebpay-api-references/blob/main/futures/api-reference/private-endpoints/trade.md#-get-open-orders
             *
             * @param {string} $symbol unified market $symbol of the market orders were made in
             * @param {int} [$since] the earliest time in ms to fetch orders for
             * @param {int} [$limit] the maximum number of order structures to retrieve
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {Order[]} a list of ~@link https://docs.ccxt.com/#/?id=order-structure order structures~
             */
            Async\await($this->load_markets());
            return Async\await($this->fetch_orders_by_status('open', $symbol, $since, $limit, $params));
        }) ();
    }

    public function fetch_order(?string $id, ?string $symbol = null, $params = array ()) {
        return Async\async(function () use ($id, $symbol, $params) {
            /**
             * fetches information on an order made by the user
             *
