    public function parse_positions($response, ?array $symbols = null, $params = array ()) {
        $result = array();
        $positions = $this->safe_value($response, 'data');
        for ($i = 0; $i < count($positions); $i++) {
            $position = $this->parse_position($positions[$i]);
            $result[] = $position;
        }
        return $result;
    }

    public function parse_position(array $position, ?array $market = null) {
        //
        // isolated
        //    {
        //        "id":"long",
        //        "symbol":"pf_ftmusd",
        //        "entryPrice":"0.4921",
        //        "datetime":"2023-02-22T11:37:16.685Z",
        //        "contractSize":"1",
        //        "leverage":"1.0"
        //    }
        //
        $leverage = $this->safe_number($position, 'leverage');
        $datetime = $this->safe_string($position, 'datetime');
        $marketId = $this->safe_string($position, 'symbol');
        $market = $this->safe_market($marketId, $market);
        return array(
            'info' => $position,
            'symbol' => $market['symbol'],
            'timestamp' => $this->parse8601($datetime),
            'datetime' => $datetime,
            'initialMargin' => null,
            'initialMarginPercentage' => null,
            'maintenanceMargin' => null,
            'maintenanceMarginPercentage' => null,
            'entryPrice' => $this->safe_number($position, 'entryPrice'),
            'notional' => null,
            'leverage' => $leverage,
            'unrealizedPnl' => null,
            'contracts' => $this->safe_number($position, 'contracts'),
            'contractSize' => $this->safe_number($market, 'contractSize'),
            'marginRatio' => null,
            'liquidationPrice' => null,
            'markPrice' => null,
            'collateral' => null,
            'marginType' => 'isolated',
            'side' => $this->safe_string($position, 'side'),
            'percentage' => null,
        );
    }

    public function parse_leverage(array $leverage, ?array $market = null): array {
        $marketId = $this->safe_string($leverage, 'symbol');
        $info = $this->safe_dict($leverage, 'info');
        $leverageValue = $this->safe_integer($leverage, 'longLeverage');
        $leverageValueShort = $this->safe_integer($leverage, 'shortLeverage');
        $marginMode = $this->safe_string($leverage, 'marginMode');
        return array(
            'info' => $info,
            'symbol' => $this->safe_symbol($marketId, $market),
            'marginMode' => $marginMode,
            'longLeverage' => $leverageValue,
            'shortLeverage' => $leverageValueShort,
        );
    }

    public function parse_order(array $order, ?array $market = null): array {
        //
        //      {
        //          "clientOrderId" => "64507d02921f1c0001ff6892-123-zeb",
        //          "datetime" => "2025-03-14T14:34:34.4567",
        //          "timestamp" => 1741962557553,
        //          "status" => "open",
        //          "symbol" => "BTCINR",
        //          "type" => "market",
        //          "timeInForce" => "GTC",
        //          "side" => "buy",
        //          "price" => 700000,
        //          "amount" => 0.002,
        //          "filled" => null,
        //          "remaining" => 0.002,
        //          "trades" => array()
        //      }
        //
        $marketId = $this->safe_string($order, 'symbol');
        $market = $this->safe_market($marketId, $market);
        $symbol = $market['symbol'];
        $type = $this->safe_string($order, 'type');
        $timestamp = $this->safe_integer($order, 'timestamp');
        $datetime = $this->iso8601($timestamp);
        $price = $this->safe_string($order, 'price');
        $side = $this->safe_string($order, 'side');
        $amount = $this->safe_string($order, 'amount');
        $clientOrderId = $this->safe_string($order, 'clientOrderId');
        $timeInForce = $this->safe_string($order, 'timeInForce');
        $status = $this->safe_string($order, 'status');
        return $this->safe_order(array(
            'id' => null,
            'clientOrderId' => $clientOrderId,
            'symbol' => $symbol,
            'type' => $type,
            'timeInForce' => $timeInForce,
            'postOnly' => null,
            'reduceOnly' => null,
            'side' => $side,
            'amount' => $amount,
            'price' => $price,
            'triggerPrice' => null,
            'cost' => null,
            'filled' => null,
            'remaining' => null,
            'timestamp' => $timestamp,
            'datetime' => $datetime,
            'fee' => null,
            'status' => $status,
            'info' => $order,
            'lastTradeTimestamp' => null,
            'lastUpdateTimestamp' => null,
            'average' => null,
            'trades' => null,
        ), $market);
    }

    public function parse_margin_modification($info, ?array $market = null): array {
        //
        //    {
        //         "symbol" => "BTCINR",
        //         "type" => "reduce",
        //         "amount" => 1000,
        //         "code" => "INR",
        //         "status" => "ok"
        //    }
        //
        $timestamp = Date.now ();
        return array(
            'info' => $info,
            'symbol' => $this->safe_string($info, 'symbol'),
            'type' => null,
            'marginMode' => null,
            'amount' => $this->safe_number($info, 'amount'),
            'total' => null,
            'code' => $this->safe_string($info, 'code'),
            'status' => $this->safe_string($info, 'status'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
        );
    }

    public function parse_balance($response): array {
        $result = array(
            'info' => $response,
            'timestamp' => null,
            'datetime' => null,
        );
        $currencyList = $this->safe_list($response, 'data');
        for ($i = 0; $i < count($currencyList); $i++) {
            $entry = $currencyList[$i];
            $account = $this->account();
            $account['total'] = $this->safe_string($entry, 'total');
            $account['free'] = $this->safe_string($entry, 'free');
            $account['used'] = $this->safe_string($entry, 'used');
            $currencyId = $this->safe_string($entry, 'currency');
            $code = $this->safe_currency_code($currencyId);
            $result[$code] = $account;
        }
        return $this->safe_balance($result);
    }

    public function parse_trading_fee(array $fee, ?array $market = null): array {
        //
        //     {
        //         "symbol" => "ETHUSDT",
        //         "makerFee" => 0.001,
        //         "takerFee" => 0.001
        //     }
        //
        $marketId = $this->safe_string($fee, 'symbol');
        $defaultType = ($market !== null) ? $market['type'] : 'contract';
        $symbol = $this->safe_symbol($marketId, $market, null, $defaultType);
        return array(
            'info' => $fee,
            'symbol' => $symbol,
            'maker' => $this->safe_number($fee, 'makerFee'),
            'taker' => $this->safe_number($fee, 'takerFee'),
            'percentage' => null,
            'tierBased' => null,
        );
    }

    public function parse_ticker(array $ticker, ?array $market = null): array {
        //
        //     {
        //          "symbol" => "BTCUSD",
        //          "timestamp" => 1672387200000,
        //          "high" => 16598,
        //          "low" => 16596,
        //          "vwap" => 16464,
        //          "open" => 7510038,
        //          "close" => 7379567,
        //          "last" => 7379530,
        //          "change" => -100,
        //          "c" => 1.5,
        //          "average" => 7444748,
        //          "baseVolume" => 326630.508,
        //          "quoteVolume" => 26892164893
        //     }
        //
        $timestamp = $this->safe_integer($ticker, 'timestamp');
        $marketType = 'contract';
        $marketId = $this->safe_string($ticker, 'symbol');
        $symbol = $this->safe_symbol($marketId, $market, null, $marketType);
        $last = $this->safe_integer($ticker, 'last');
        $avg = $this->safe_integer($ticker, 'average');
        $baseVolume = $this->safe_integer($ticker, 'baseVolume');
        $quoteVolume = $this->safe_integer($ticker, 'quoteVolume');
        return $this->safe_ticker(array(
            'symbol' => $symbol,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'high' => $this->safe_integer($ticker, 'high'),
            'low' => $this->safe_integer($ticker, 'low'),
            'open' => $this->safe_integer($ticker, 'open'),
            'close' => $this->safe_integer($ticker, 'close'),
            'last' => $last,
            'previousClose' => null, // previous day close
            'change' => $this->safe_integer($ticker, 'change'),
            'percentage' => $this->safe_integer($ticker, 'safeInteger'),
            'average' => $avg,
            'baseVolume' => $baseVolume,
            'quoteVolume' => $quoteVolume,
            'info' => $ticker,
        ), $market);
    }

    public function sign($path, $api = 'public', $method = 'GET', $params = array (), $headers = null, $body = null) {
        $url = $this->urls['api'][$api];
        $versions = $this->safe_value($this->options, 'versions', array());
        $apiVersions = $this->safe_value($versions, $api, array());
        $methodVersions = $this->safe_value($apiVersions, $method, array());
        $defaultVersion = $this->safe_string($methodVersions, $path, $this->version);
        $version = $this->safe_string($params, 'version', $defaultVersion);
        $tail = '/api/' . $version . '/' . $this->implode_params($path, $params);
        $url .= $tail;
        // $timestamp = (string) $this->milliseconds();
        $signature = '';
        $query = $this->omit($params, $this->extract_params($path));
        $queryLength = $query;
        if ($api === 'public') {
            if ($queryLength) {
                $url .= '?' . $this->urlencode($query);
            }
        } else {
            $this->check_required_credentials();
            if ($method === 'GET') {
                // For GET/DELETE => Append $params to URL and sign the $query string || $method === 'DELETE'
                // $params['timestamp'] = $timestamp;
                $queryString = $this->urlencode($params);
                $signature = $this->hmac($queryString, $this->secret, 'sha256', 'hex');
                $url .= '?' . $queryString;
            } else {
                // For POST/PUT => Convert $body to JSON and sign the stringified payload
                // $params['timestamp'] = $timestamp;
                $body = json_encode ($params);
                $signature = $this->hmac($body, $this->secret, 'sha256', 'hex');
            }
            $headers = array(
                'X-AUTH-APIKEY' => $this->apiKey,
                'X-AUTH-SIGNATURE' => $signature,
            );
            $headers['Content-Type'] = 'application/json';
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }

    public function handle_errors(int $code, string $reason, string $url, string $method, array $headers, string $body, $response, $requestHeaders, $requestBody) {
        if (!$response) {
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $body, $body);
            return null;
        }
        //
        // bad
        //     array( "code" => "400100", "msg" => "validation.createOrder.clientOidIsRequired" )
        // good
        //     array( $code => "200000", data => array( ... ))
        //
        $errorCode = $this->safe_string($response, 'code');
        $message = $this->safe_string($response, 'msg', '');
        $feedback = $this->id . ' ' . $message;
        $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
        $this->throw_exactly_matched_exception($this->exceptions['exact'], $errorCode, $feedback);
        $this->throw_broadly_matched_exception($this->exceptions['broad'], $body, $feedback);
        return null;
    }
}
